sql:
SELECT initiative_id, report_period, progress_percentage, notes, financial_year_id, status
FROM progress_reports
WHERE progress_percentage > 50 AND status != 'on track';

SELECT SUM(progress_percentage) AS total_progress_percentage
FROM progress_reports
WHERE initiative_id = 1;

SELECT total_progress_current_quarter
FROM initiatives
WHERE initiative_id = 1;

external_knowledge:
- "Focus areas" are specific areas of interest or initiative within an organization;
- "Planned expenditures" refer to the budgeted or expected spending for the current year;
- "Total expenditures" is the sum of all planned expenditures for each focus area;
- "Greater than 10 million" is a threshold used to filter out focus areas with lower spending.

- "Planned expenditures" refer to the budgeted amount for the current year;
- "Actual expenditures" refer to the amount spent through the current quarter;
- "Total progress through 2025" measures the cumulative progress on expenditures up to the year 2025.

sql:
SELECT MIN(forecasted_expenditure) AS min_forecasted_expenditure
FROM budget_forecasts
WHERE forecast_year = '2024';

SELECT MAX(expenditures_plan) AS highest_planned_expenditure
FROM initiatives
WHERE focus_area = 'Clean Heat & Cooling';

SELECT SUM(expenditures_plan) AS total_planned_expenditures
FROM initiatives
WHERE focus_area = 'Energy Efficiency';

external_knowledge:
- The progress report period is Q2 2023;
- The expenditure difference is calculated as the total actual expenditures minus the planned expenditures;
- The initiative with the largest absolute value of expenditure difference is selected.

sql:
SELECT initiative_name
FROM initiatives
WHERE total_progress_through_2025 > (
  SELECT AVG(total_progress_through_2025)
  FROM initiatives
);

external_knowledge:
- 'most advanced' refers to the initiative with the highest progress percentage;
- 'current financial year' is '2023-2024';
- 'first quarter' corresponds to 'Q1 2023'.
